/**
 * HA MQTT Binary Sensor — Problem Reporter
 * Version: 1.1
 *
 * Publishes a Home Assistant MQTT discovery binary_sensor representing
 * a problem state. Designed for use with the "problem" device class.
 *
 * INPUT
 *   Simple payload (no attribute):
 *     msg.payload {string} — "on" or "off" (case-insensitive)
 *
 *   Payload with attribute (requires ATTRIBUTE_KEY to be set):
 *     msg.payload {object} — { state: "on"|"off", <ATTRIBUTE_KEY>: <value> }
 *     e.g. { state: "on", devices: ["Sensor A", "Sensor B"] }
 *     The key in msg.payload must match the ATTRIBUTE_KEY constant exactly.
 *
 * OUTPUT
 *   Two MQTT messages to wire into an MQTT Out node connected
 *   to the same broker that Home Assistant uses:
 *     [0] config topic — MQTT discovery config payload
 *     [1] state topic  — current problem state (and attributes, if configured)
 *
 * SETUP
 *   Update the constants in the "Node Configuration" section below.
 *   Generate a fresh UUID for each new problem sensor.
 *
 * CHANGELOG
 *   1.1 — Added optional ATTRIBUTE_KEY support for exposing a single HA
 *          attribute (e.g. a list of affected devices). Set ATTRIBUTE_KEY
 *          to "" or null to disable. Payload now accepts either a plain
 *          string or an object with a "state" key.
 *   1.0 — Initial release.
 */

// ── Node Configuration ────────────────────────────────────────────────────────

const UUID          = "a3ad6610-529b-403b-be6b-c6ab54a2bc9f"; // Unique identifier for this sensor (generate a fresh UUID per entity)
const NAME          = "Low Battery Problem";                   // Friendly name shown in Home Assistant
const ICON_ON       = "mdi:battery-alert";                     // Icon when problem is active
const ICON_OFF      = "mdi:check-circle";                      // Icon when problem is inactive

// Optional: set to a non-empty string to expose a single HA state attribute.
// The value must match the key used in msg.payload exactly.
// Set to "" or null if no attribute is needed.
//   e.g. "devices", "affected_zones", "error_codes"
const ATTRIBUTE_KEY = "devices";

// ── Runtime ───────────────────────────────────────────────────────────────────

// Accept either a plain string ("on"/"off") or an object ({ state, <attr> })
const value = (typeof msg.payload === "string")
    ? msg.payload.toLowerCase()
    : msg.payload.state.toLowerCase();

const baseTopic   = `homeassistant/binary_sensor/${UUID}`;
const stateTopic  = `${baseTopic}/state`;
const configTopic = `${baseTopic}/config`;
const icon        = value === "on" ? ICON_ON : ICON_OFF;

// State payload — attributes block only included when ATTRIBUTE_KEY is set
const statePayload = { value };
if (ATTRIBUTE_KEY) {
    statePayload.attributes = {
        [ATTRIBUTE_KEY]: msg.payload[ATTRIBUTE_KEY] ?? null
    };
}

// Config payload — attribute discovery fields only included when needed
const configPayload = {
    name:           NAME,
    icon:           icon,
    unique_id:      UUID,
    state_topic:    stateTopic,
    device_class:   "problem",
    payload_on:     "on",
    payload_off:    "off",
    value_template: "{{ value_json.value }}"
};
if (ATTRIBUTE_KEY) {
    configPayload.json_attributes_topic    = stateTopic;
    configPayload.json_attributes_template = "{{ value_json.attributes | tojson }}";
}

const messages = [[
    { topic: configTopic, payload: configPayload },
    { topic: stateTopic,  payload: statePayload  }
]];

setNodeStatus(value);
return messages;

// ── Helpers ───────────────────────────────────────────────────────────────────

/**
 * Updates the Node-RED node status badge with the current state and timestamp.
 *
 * @param {string} state  - Label to display (e.g. "on" / "off")
 * @param {string} color  - Badge colour (default: "green")
 * @param {string} shape  - Badge shape: "dot" or "ring" (default: "dot")
 */
function setNodeStatus(state, color = "green", shape = "dot") {
    const now     = new Date();
    const day     = now.getDate();
    const month   = now.toLocaleString("en-US", { month: "short" });
    const hours   = String(now.getHours()).padStart(2, "0");
    const minutes = String(now.getMinutes()).padStart(2, "0");

    node.status({
        fill:  color,
        shape: shape,
        text:  `${state} at: ${day}-${month}, ${hours}:${minutes}`
    });
}
